#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int m, n; scanf("%d %d", &m, &n);
        int a[10][10];
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                scanf("%d", &a[i][j]);
            }
        }
        int top = 0, bottom = m - 1, left = 0, right = n - 1;
        int first = 1;
        while (top <= bottom && left <= right) {
            for (int j = left; j <= right; ++j) {
                if (!first) printf(" ");
                printf("%d", a[top][j]);
                first = 0;
            }
            ++top;
            for (int i = top; i <= bottom; ++i) {
                printf(" %d", a[i][right]);
            }
            --right;
            if (top <= bottom) {
                for (int j = right; j >= left; --j) {
                    printf(" %d", a[bottom][j]);
                }
                --bottom;
            }
            if (left <= right) {
                for (int i = bottom; i >= top; --i) {
                    printf(" %d", a[i][left]);
                }
                ++left;
            }
        }
        printf("\n");
    }
    return 0;
}

